class RecordingCoachMarks {
  static const double borderRadius = 8.0;
  static const Color primaryColor = Color(0xFF0052CC);
  static const Color backgroundColor = Color(0xFF091E42);

  static List<TargetFocus> createTargets({
    required BuildContext context,
    required GlobalKey recordButtonKey,
    required GlobalKey analysisModeKey,
    required GlobalKey focusButtonKey,
    required GlobalKey configurationKey,
    GlobalKey? graphExampleKey,
    void Function(int currentStep, int totalSteps)? onStepChange,
    VoidCallback? onLaunchUrl,
  }) {
    final l10n = context.l10n;
    return [
      // Record button
      TargetFocus(
        identify: "record",
        keyTarget: recordButtonKey,
        shape: ShapeLightFocus.Circle,
        contents: [
          TargetContent(
            align: ContentAlign.top,
            builder: (context, controller) {
              return _buildContentCard(
                context: context,
                title: l10n.recording_coach_marks__record_title,
                description: l10n.recording_coach_marks__record_description,
                icon: Icons.fiber_manual_record_outlined,
                tips: [
                  l10n.recording_coach_marks__record_tip_tripod,
                  l10n.recording_coach_marks__record_tip_environment,
                  l10n.recording_coach_marks__record_tip_distance,
                ],
                isLast: true,
                currentStep: 1,
                totalSteps: 3,
                onNext: () {
                  onStepChange?.call(1, 3);
                  controller.next();
                },
                onLaunchUrl: onLaunchUrl,
              );
            },
          ),
        ],
      ),

      // Analysis mode selection
      TargetFocus(
        identify: "analysis_mode",
        keyTarget: analysisModeKey,
        shape: ShapeLightFocus.Circle,
        radius: borderRadius,
        contents: [
          TargetContent(
            align: ContentAlign.top,
            builder: (context, controller) {
              return _buildContentCard(
                context: context,
                title: l10n.recording_coach_marks__analysis_mode_title,
                description:
                    l10n.recording_coach_marks__analysis_mode_description,
                icon: Icons.settings_outlined,
                tips: [
                  l10n.recording_coach_marks__analysis_mode_tip_pitching,
                  l10n.recording_coach_marks__analysis_mode_tip_hitting,
                ],
                currentStep: 2,
                totalSteps: 3,
                onNext: () {
                  onStepChange?.call(2, 3);
                  controller.next();
                },
                onLaunchUrl: onLaunchUrl,
              );
            },
          ),
        ],
      ),

      // Focus settings
      TargetFocus(
        identify: "focus",
        keyTarget: focusButtonKey,
        shape: ShapeLightFocus.Circle,
        radius: borderRadius,
        contents: [
          TargetContent(
            align: ContentAlign.top,
            builder: (context, controller) {
              return _buildContentCard(
                context: context,
                title: l10n.recording_coach_marks__focus_title,
                description: l10n.recording_coach_marks__focus_description,
                icon: Icons.center_focus_strong_outlined,
                tips: [
                  l10n.recording_coach_marks__focus_tip_af_to_mf,
                  l10n.recording_coach_marks__focus_tip_behind_pitcher,
                  l10n.recording_coach_marks__focus_tip_behind_catcher,
                ],
                currentStep: 3,
                totalSteps: graphExampleKey != null ? 4 : 3,
                onNext: () {
                  onStepChange?.call(3, graphExampleKey != null ? 4 : 3);
                  controller.next();
                },
                onLaunchUrl: onLaunchUrl,
              );
            },
          ),
        ],
      ),
      // Graph example (optional)
      if (graphExampleKey != null)
        TargetFocus(
          identify: "graph_example",
          keyTarget: graphExampleKey,
          shape: ShapeLightFocus.RectAngle,
          radius: borderRadius,
          contents: [
            TargetContent(
              align: ContentAlign.top,
              builder: (context, controller) {
                return _buildImageCard(
                  context: context,
                  title: l10n.recording_coach_marks__graph_example_title,
