                      l10n.recording_coach_marks__graph_example_description,
                  image: Assets.images.imgGraphJa.path,
                  currentStep: 4,
                  totalSteps: 4,
                  onNext: () {
                    onStepChange?.call(4, 4);
                    controller.next();
                  },
                  onLaunchUrl: onLaunchUrl,
                );
              },
            ),
          ],
        ),
    ];
  }

